let d = msg.payload_decoded || msg.payload;

if (!d || !d.foto_A || !d.foto_B) return msg;

// =======================================================
// 1. MAPA LINEAL DEL TÚNEL
// Minor = PK
// Major = nivel
// =======================================================

const mapaPK = {
    0: 0,
    20: 20,
    40: 40,
    60: 60,
    80: 80,
    100: 100
};

function calcularPeso(rssi) {
    if (rssi === 0 || rssi < -95) return 0.01;
    return Math.pow(10, ((rssi + 100) / 20));
}

function calcularPosicionLineal(foto) {
    let sumaPesos = 0;
    let sumaDistancia = 0;

    for (let key in foto) {
        let b = foto[key];

        if (b && b.valid) {
            // Ahora el PK viene desde el Minor.
            // El Major ya no se usa para calcular la posición lineal.
            let pk = Number(b.minor);

            if (mapaPK[pk] !== undefined) {
                let peso = calcularPeso(b.rssi);
                sumaDistancia += mapaPK[pk] * peso;
                sumaPesos += peso;
            }
        }
    }

    if (sumaPesos === 0) return null;
    return sumaDistancia / sumaPesos;
}

// =======================================================
// 1.1 OBTENER BEACON MÁS FUERTE
// Major = nivel
// Minor = PK
// RSSI  = intensidad
// =======================================================

function obtenerBeaconMasFuerte(d) {
    let beacons = [];

    function agregar(foto) {
        if (!foto) return;

        for (let key in foto) {
            let b = foto[key];

            if (b && b.valid && b.rssi !== 0) {
                beacons.push({
                    major: Number(b.major),
                    minor: Number(b.minor),
                    rssi: Number(b.rssi)
                });
            }
        }
    }

    // Foto B es la lectura más actual.
    // Foto A queda como respaldo.
    agregar(d.foto_B);
    agregar(d.foto_A);

    if (beacons.length === 0) return null;

    // RSSI más alto = señal más fuerte.
    // Ejemplo: -45 es más fuerte que -80.
    beacons.sort((a, b) => b.rssi - a.rssi);

    return beacons[0];
}

let beaconFuerte = obtenerBeaconMasFuerte(d);

let major_actual = beaconFuerte ? beaconFuerte.major : null;
let minor_actual = beaconFuerte ? beaconFuerte.minor : null;
let rssi_beacon_mayor = beaconFuerte ? beaconFuerte.rssi : null;

// =======================================================
// 2. CÁLCULO DE POSICIÓN
// =======================================================

let posA_cruda = calcularPosicionLineal(d.foto_A);
let posB_cruda = calcularPosicionLineal(d.foto_B);

// Si no hay PK válido, no calculamos Kalman.
// Pero igual dejamos guardado el nivel si existe un beacon válido.
if (posB_cruda === null) {
    msg.trayectoria = msg.trayectoria || {};

    msg.trayectoria.major_actual = major_actual;
    msg.trayectoria.nivel_actual = major_actual;
    msg.trayectoria.minor_actual = minor_actual;
    msg.trayectoria.pk_beacon_mas_fuerte = minor_actual;
    msg.trayectoria.rssi_beacon_mayor = rssi_beacon_mayor;

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `Sin PK válido | Nivel ${major_actual ?? "-"}`
    });

    return msg;
}

// =======================================================
// 3. FILTRO DE KALMAN
// =======================================================

const R = 8.0;
const Q = 0.5;

let kalmanKey = d.dev_eui || d.node_id || d.device_name || "default";

let x_est = context.get("kalman_x_" + kalmanKey);
let P = context.get("kalman_P_" + kalmanKey);

if (x_est === undefined || x_est === null) {
    x_est = posB_cruda;
    P = 1.0;
}

let x_pred = x_est;
let P_pred = P + Q;

let K = P_pred / (P_pred + R);

x_est = x_pred + K * (posB_cruda - x_pred);
P = (1 - K) * P_pred;

context.set("kalman_x_" + kalmanKey, x_est);
context.set("kalman_P_" + kalmanKey, P);

// Limitar la posición dentro del túnel.
// Si después usas PK mayores a 100, cambia este límite.
x_est = Math.max(0, Math.min(100, x_est));

// =======================================================
// 4. TENDENCIA Y PREDICCIÓN POR TRAMO PK
// =======================================================

let prediccion = x_est;
let estado_movimiento = "Calculando...";

const pks = [0, 20, 40, 60, 80, 100];

let pk_inferior = 0;
let pk_superior = 20;

for (let i = 0; i < pks.length - 1; i++) {
    if (x_est >= pks[i] && x_est <= pks[i + 1]) {
        pk_inferior = pks[i];
        pk_superior = pks[i + 1];
        break;
    }
}

if (posA_cruda !== null) {
    let diferencia = x_est - posA_cruda;

    prediccion = Math.max(0, Math.min(100, x_est + diferencia));

    if (diferencia > 2.0) {
        estado_movimiento = `Saliendo del PK ${pk_inferior}, entrando al PK ${pk_superior}`;
    } else if (diferencia < -2.0) {
        estado_movimiento = `Saliendo del PK ${pk_superior}, entrando al PK ${pk_inferior}`;
    } else {
        let pk_cercano = (x_est - pk_inferior < pk_superior - x_est) ? pk_inferior : pk_superior;
        estado_movimiento = `Detenido cerca del PK ${pk_cercano}`;
    }
}

// =======================================================
// 5. EMPAQUETAR RESULTADO
// =======================================================

msg.trayectoria = {
    metro_actual_crudo: parseFloat(posB_cruda.toFixed(2)),
    metro_actual_kalman: parseFloat(x_est.toFixed(2)),
    metro_prediccion: parseFloat(prediccion.toFixed(2)),
    incertidumbre: parseFloat(P.toFixed(2)),
    estado: estado_movimiento,

    // Posición anterior desde Foto A
    metro_anterior_crudo: posA_cruda !== null ? parseFloat(posA_cruda.toFixed(2)) : null,

    // Alias para Mapear_Modbus_Multi y SQL
    posicion_actual: parseFloat(x_est.toFixed(2)),
    posicion_anterior: posA_cruda !== null ? parseFloat(posA_cruda.toFixed(2)) : null,
    posicion_futura: parseFloat(prediccion.toFixed(2)),

    // NUEVO:
    // Major = nivel
    // Minor = PK
    major_actual: major_actual,
    nivel_actual: major_actual,
    minor_actual: minor_actual,
    pk_beacon_mas_fuerte: minor_actual,
    rssi_beacon_mayor: rssi_beacon_mayor
};

// Estado visual para confirmar que el filtro está enviando datos
node.status({
    fill: "green",
    shape: "dot",
    text: `Nivel ${major_actual ?? "-"} | PK actual: ${msg.trayectoria.posicion_actual} m`
});

return msg;
